VALUES
  ('locality-d0d1b9a2-moex-00274', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司生產10,000單位，投入製造費用總計$240,000，標準機器小時為29,700小時，實際機 器小時為30,000小時。固定製造費用之預算為$57,600，固定製造費用之用款差異（spending variance）為不利$3,150，若變動製造費用每機器小時之預計分攤率為$6，下列何者為變動製 造費用用款差異？', '["$750有利", "$750不利", "$1,050有利", "$1,050不利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00275', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司計劃推出新產品，市場調查資料顯示，若單位售價訂為$75，則每年可產銷 10,000 單 位。製造該產品需投資$800,000，公司的期望報酬率為20%，預計銷管費用為$150,000。下列 何者為每年之總目標製造成本？', '["$160,000", "$440,000", "$590,000", "$600,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00276', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲印刷公司正考慮汰換舊電腦，舊電腦帳面價值$24,000，供應商願意回收舊電腦並折抵 $14,000後，以$85,000之價格提供甲印刷公司新電腦。新電腦估計每年可節省$20,000之營業 成本。若甲印刷公司決定不汰舊換新，則省下的$85,000可用於償還負債，每年可少支付利息 $9,000。下列何者為此決策之沉沒成本？', '["少支付之利息", "可節省之營業成本", "舊電腦的帳面價值", "舊電腦的折抵價值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00277', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '有關成本抑減可能之方法，下列何者錯誤？', '["簡化製造流程", "提升製造效率", "增加產品功能", "減少無附加價值之活動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00278', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '有關資本預算決策之淨現值法及內部報酬率法，下列敘述何者錯誤？', '["當淨現值大於0時則可接受該投資計畫", "當內部報酬率等於公司資金成本率則淨現值等於0", "內部報酬率法對再投資報酬率的假設相當不合理", "當內部報酬率小於資金成本率時則可接受該投資計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00279', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司對A零件之需求量為每個月5,000單位，公司生產部目前配置之人力，均已充分使用， 故若欲自製 A 零件，則須加班生產，正常工資率為每小時$120，加班之工資率則為每小時 $180，加班不影響固定製造費用。甲公司自製 1 單位 A 零件需要 3 單位材料及 2 個人工小 時，材料單位價格為$150，製造費用係以直接人工小時為分攤基礎，每人工小時應分攤之變 動及固定製造費用分別為$80及$100。今有一廠商願意生產A零件提供給甲公司，在利潤考 量下，下列何者為外購A零件每單位可接受之最高價格？', '["$610", "$850", "$970", "$1,170"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00280', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '有關平衡計分卡之構面，下列何者屬於內部程序構面指標？', '["財務比率", "市場占有率", "顧客滿意度", "製造循環時間"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00281', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司銷售民生必需品，其每單位持有成本為$5，每次訂購成本為$50。由於嚴重通膨，預期 訂購成本增加25%，持有成本增加25%，下列何者為通膨造成之經濟訂購量變化？', '["無變化", "增加5%", "增加25%", "增加50%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00282', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '有關作業基礎成本制，下列敘述何者錯誤？', '["資源要素即為會計科目之相關費用", "作業中心要儘可能區分出作業之差異性", "成本標的可為產品、顧客、計畫或部門等", "辦公室之租金若以作業中心之坪數為分攤基礎，則坪數為作業動因"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00283', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-112-194ec0d9', 'sub-locality-d0d1b9a2-06', NULL, 'single_choice', '甲公司總裁下令公司任何的投資方案，皆需要有8%之投資報酬率。公司設有A與B兩部門 分權經營。各部門經理對任何報酬率高於 8%的投資方案具有裁決權。A 部門過去 3 年之投 資報酬率皆為14%且預期未來也能繼續維持。A部門有一新投資方案，預期可產生12%之投 資報酬率。若總裁以剩餘利益評估部門績效，下列敘述何者正確？', '["A部門經理接受此投資方案，與總裁目標一致", "A部門經理拒絕此投資方案，與總裁目標一致", "A部門經理接受此投資方案，與總裁目標不一致", "A部門經理拒絕此投資方案，與總裁目標不一致"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:07+00:00", "source_pdf_sha1": "42b9bd14c112", "answer_pdf_sha1": "2b6da5361def", "source_family": "moex-gov-tw", "moex": {"exam_code": "112200", "c": "314", "s": "1705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本與管理會計", "year": "112", "exam_name": "112年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
